DEFAULT_EMBED_MODEL = os.getenv("RAG_EMBED_MODEL", "text-embedding-3-large")
DEFAULT_CHAT_MODEL = os.getenv("RAG_CHAT_MODEL", "gpt-4.1-mini")


def sha256_text(s: str) -> str:
    return hashlib.sha256(s.encode("utf-8")).hexdigest()


def now_ms() -> int:
    return int(time.time() * 1000)


def ensure_dir(p: str) -> None:
    os.makedirs(p, exist_ok=True)


def read_text_file(path: str) -> str:
    with open(path, "r", encoding="utf-8", errors="ignore") as f:
        return f.read()


def list_files(root: str, patterns: List[str]) -> List[str]:
    files = []
    for pat in patterns:
        files.extend(glob.glob(os.path.join(root, pat), recursive=True))
    files = [f for f in files if os.path.isfile(f)]
    files.sort()
    return files


def estimate_tokens(text: str, model: str = DEFAULT_CHAT_MODEL) -> int:
    if tiktoken is None:
        return max(1, len(text) // 4)
    try:
        enc = tiktoken.encoding_for_model(model)
    except Exception:
        enc = tiktoken.get_encoding("cl100k_base")
    return len(enc.encode(text))


def chunk_text(
    text: str,
    target_tokens: int = 700,
    overlap_tokens: int = 120,
    model: str = DEFAULT_CHAT_MODEL,
) -> List[str]:
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    if not text.strip():
        return []

    if tiktoken is None:
        approx_chars = max(200, target_tokens * 4)
        overlap_chars = max(0, overlap_tokens * 4)
        chunks = []
        start = 0
        n = len(text)
        while start < n:
            end = min(n, start + approx_chars)
            chunk = text[start:end].strip()
            if chunk:
                chunks.append(chunk)
            if end == n:
                break
            start = max(0, end - overlap_chars)
        return chunks

    try:
        enc = tiktoken.encoding_for_model(model)
    except Exception:
        enc = tiktoken.get_encoding("cl100k_base")

    toks = enc.encode(text)
    chunks = []
    start = 0
    n = len(toks)
    while start < n:
        end = min(n, start + target_tokens)
        chunk_toks = toks[start:end]
        chunk = enc.decode(chunk_toks).strip()
        if chunk:
            chunks.append(chunk)
        if end == n:
            break
        start = max(0, end - overlap_tokens)
    return chunks


def cosine_sim_matrix(a: np.ndarray, b: np.ndarray) -> np.ndarray:
    a_norm = a / (np.linalg.norm(a, axis=1, keepdims=True) + 1e-12)
    b_norm = b / (np.linalg.norm(b, axis=1, keepdims=True) + 1e-12)
    return a_norm @ b_norm.T


@dataclass
class DocChunk:
    id: str
    doc_id: str
    source_path: str
    title: str
    chunk_index: int
    text: str
    text_hash: str
    tokens: int
    created_at_ms: int


class SQLiteVectorStore:
    def __init__(self, db_path: str):
        self.db_path = db_path
        ensure_dir(os.path.dirname(os.path.abspath(db_path)) or ".")
        self._lock = threading.RLock()
        self._conn = sqlite3.connect(db_path, check_same_thread=False)
        self._conn.execute("PRAGMA journal_mode=WAL;")
        self._conn.execute("PRAGMA synchronous=NORMAL;")
        self._conn.execute("PRAGMA temp_store=MEMORY;")
        self._init_schema()

    def close(self):
        with self._lock:
            self._conn.commit()
            self._conn.close()

    def _init_schema(self):
        with self._lock:
            cur = self._conn.cursor()
            cur.execute(
                """
                CREATE TABLE IF NOT EXISTS chunks (
                    id TEXT PRIMARY KEY,
                    doc_id TEXT NOT NULL,
                    source_path TEXT NOT NULL,
                    title TEXT,
                    chunk_index INTEGER NOT NULL,
                    text TEXT NOT NULL,
                    text_hash TEXT NOT NULL,
                    tokens INTEGER NOT NULL,
                    created_at_ms INTEGER NOT NULL
                );
                """
            )
            cur.execute(
                """
                CREATE UNIQUE INDEX IF NOT EXISTS idx_chunks_doc_chunk
                ON chunks(doc_id, chunk_index);
                """
            )
            cur.execute(
                """
                CREATE INDEX IF NOT EXISTS idx_chunks_source
                ON chunks(source_path);
                """
            )
            cur.execute(
                """
                CREATE TABLE IF NOT EXISTS embeddings (
                    chunk_id TEXT PRIMARY KEY,
                    model TEXT NOT NULL,
                    dim INTEGER NOT NULL,
                    vector BLOB NOT NULL,
                    created_at_ms INTEGER NOT NULL,
                    FOREIGN KEY(chunk_id) REFERENCES chunks(id) ON DELETE CASCADE
                );
                """
            )
            cur.execute(
                """
                CREATE INDEX IF NOT EXISTS idx_embeddings_model
                ON embeddings(model);
                """
            )
            self._conn.commit()

    @staticmethod
    def _vec_to_blob(vec: np.ndarray) -> bytes:
        vec = np.asarray(vec, dtype=np.float32)
        return vec.tobytes()

    @staticmethod
    def _blob_to_vec(blob: bytes, dim: int) -> np.ndarray:
        arr = np.frombuffer(blob, dtype=np.float32)
        if dim > 0 and arr.size != dim:
            arr = arr[:dim]
        return arr

    def upsert_chunk(self, chunk: DocChunk) -> None:
        with self._lock:
            self._conn.execute(
                """
                INSERT INTO chunks (id, doc_id, source_path, title, chunk_index, text, text_hash, tokens, created_at_ms)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(id) DO UPDATE SET
                    doc_id=excluded.doc_id,
                    source_path=excluded.source_path,
                    title=excluded.title,
                    chunk_index=excluded.chunk_index,
                    text=excluded.text,
                    text_hash=excluded.text_hash,
                    tokens=excluded.tokens
                ;
                """,
                (
                    chunk.id,
                    chunk.doc_id,
                    chunk.source_path,
                    chunk.title,
                    chunk.chunk_index,
                    chunk.text,
                    chunk.text_hash,
                    chunk.tokens,
                    chunk.created_at_ms,
                ),
            )
            self._conn.commit()

    def upsert_embedding(self, chunk_id: str, model: str, vec: np.ndarray) -> None:
        vec = np.asarray(vec, dtype=np.float32)
        with self._lock:
            self._conn.execute(
                """
                INSERT INTO embeddings (chunk_id, model, dim, vector, created_at_ms)
                VALUES (?, ?, ?, ?, ?)
                ON CONFLICT(chunk_id) DO UPDATE SET
                    model=excluded.model,
                    dim=excluded.dim,
                    vector=excluded.vector,
                    created_at_ms=excluded.created_at_ms
                ;
                """,
                (chunk_id, model, int(vec.size), self._vec_to_blob(vec), now_ms()),
            )
            self._conn.commit()

    def get_chunk_by_id(self, chunk_id: str) -> Optional[DocChunk]:
        with self._lock:
            row = self._conn.execute(
                """
                SELECT id, doc_id, source_path, title, chunk_index, text, text_hash, tokens, created_at_ms
                FROM chunks WHERE id = ?;
                """,
                (chunk_id,),
            ).fetchone()
        if not row:
            return None
        return DocChunk(
            id=row[0],
            doc_id=row[1],
            source_path=row[2],
            title=row[3] or "",
            chunk_index=int(row[4]),
            text=row[5],
            text_hash=row[6],
            tokens=int(row[7]),
            created_at_ms=int(row[8]),
        )

    def get_all_embeddings(self, model: str) -> Tuple[List[str], np.ndarray, List[DocChunk]]:
        with self._lock:
            rows = self._conn.execute(
                """
                SELECT e.chunk_id, e.dim, e.vector,
                       c.id, c.doc_id, c.source_path, c.title, c.chunk_index, c.text, c.text_hash, c.tokens, c.created_at_ms
                FROM embeddings e
                JOIN chunks c ON c.id = e.chunk_id
                WHERE e.model = ?
                ORDER BY c.source_path, c.chunk_index;
                """,
                (model,),
            ).fetchall()
        chunk_ids = []
        vecs = []
        chunks = []
        for r in rows:
            chunk_id, dim, blob = r[0], int(r[1]), r[2]
            c = DocChunk(
                id=r[3],
                doc_id=r[4],
                source_path=r[5],
                title=r[6] or "",
                chunk_index=int(r[7]),
                text=r[8],
                text_hash=r[9],
                tokens=int(r[10]),
                created_at_ms=int(r[11]),
            )
            chunk_ids.append(chunk_id)
            vecs.append(self._blob_to_vec(blob, dim))
            chunks.append(c)
        if vecs:
            mat = np.vstack([v.reshape(1, -1) for v in vecs]).astype(np.float32)
        else:
            mat = np.zeros((0, 0), dtype=np.float32)
        return chunk_ids, mat, chunks

    def get_existing_chunk_by_hash(self, doc_id: str, chunk_index: int) -> Optional[Tuple[str, str]]:
        with self._lock:
            row = self._conn.execute(
                """
                SELECT id, text_hash FROM chunks
                WHERE doc_id = ? AND chunk_index = ?;
                """,
                (doc_id, chunk_index),
            ).fetchone()
        if not row:
            return None
        return row[0], row[1]

    def delete_doc(self, doc_id: str) -> None:
        with self._lock:
            self._conn.execute("DELETE FROM embeddings WHERE chunk_id IN (SELECT id FROM chunks WHERE doc_id = ?);", (doc_id,))
            self._conn.execute("DELETE FROM chunks WHERE doc_id = ?;", (doc_id,))
            self._conn.commit()

    def stats(self) -> Dict[str, Any]:
        with self._lock:
            c1 = self._conn.execute("SELECT COUNT(*) FROM chunks;").fetchone()[0]
            c2 = self._conn.execute("SELECT COUNT(*) FROM embeddings;").fetchone()[0]
            return {"chunks": int(c1), "embeddings": int(c2), "db_path": self.db_path}


class RAG:
    def __init__(
        self,
        store: SQLiteVectorStore,
        openai_client: OpenAI,
        embed_model: str = DEFAULT_EMBED_MODEL,
        chat_model: str = DEFAULT_CHAT_MODEL,
    ):
        self.store = store
        self.client = openai_client
        self.embed_model = embed_model
        self.chat_model = chat_model

    def embed_texts(self, texts: List[str], batch_size: int = 128) -> np.ndarray:
        if not texts:
            return np.zeros((0, 0), dtype=np.float32)
        all_vecs = []
        for i in range(0, len(texts), batch_size):
            batch = texts[i : i + batch_size]
            resp = self.client.embeddings.create(model=self.embed_model, input=batch)
            vecs = [np.asarray(d.embedding, dtype=np.float32) for d in resp.data]
            all_vecs.extend(vecs)
        mat = np.vstack([v.reshape(1, -1) for v in all_vecs]).astype(np.float32)
        return mat

    def index_directory(
        self,
        docs_path: str,
        patterns: List[str],
        chunk_tokens: int = 700,
        overlap_tokens: int = 120,
        title_from_path: bool = True,
        delete_missing: bool = False,
    ) -> Dict[str, Any]:
        files = list_files(docs_path, patterns)
        doc_ids = [sha256_text(os.path.abspath(p)) for p in files]
        seen_doc_ids = set(doc_ids)

        if delete_missing:
            with self.store._lock:
                rows = self.store._conn.execute("SELECT DISTINCT doc_id, source_path FROM chunks;").fetchall()
            for doc_id, src in rows:
                if doc_id not in seen_doc_ids:
                    self.store.delete_doc(doc_id)

        total_chunks = 0
        embedded_new = 0
        updated_chunks = 0
        skipped_unchanged = 0

        to_embed_texts = []
        to_embed_chunk_ids = []

        for path in files:
            abspath = os.path.abspath(path)
            doc_id = sha256_text(abspath)
            title = os.path.basename(path) if title_from_path else ""

            try:
                text = read_text_file(path)
            except Exception:
                continue

            chunks = chunk_text(text, target_tokens=chunk_tokens, overlap_tokens=overlap_tokens, model=self.chat_model)
            for idx, ch in enumerate(chunks):
                th = sha256_text(ch)
                existing = self.store.get_existing_chunk_by_hash(doc_id, idx)
                if existing and existing[1] == th:
                    skipped_unchanged += 1
                    total_chunks += 1
                    continue

                chunk_id = existing[0] if existing else str(uuid.uuid4())
                dc = DocChunk(
                    id=chunk_id,
                    doc_id=doc_id,
                    source_path=abspath,
                    title=title,
                    chunk_index=idx,
                    text=ch,
                    text_hash=th,
                    tokens=estimate_tokens(ch, self.chat_model),
                    created_at_ms=now_ms(),
                )
                self.store.upsert_chunk(dc)
                updated_chunks += 1
                total_chunks += 1
                to_embed_texts.append(ch)
                to_embed_chunk_ids.append(chunk_id)

        if to_embed_texts:
            mat = self.embed_texts(to_embed_texts)
            for i, chunk_id in enumerate(to_embed_chunk_ids):
                self.store.upsert_embedding(chunk_id, self.embed_model, mat[i])
            embedded_new = len(to_embed_chunk_ids)

        return {
            "files": len(files),
            "total_chunks_processed": total_chunks,
            "chunks_updated_or_added": updated_chunks,
            "chunks_skipped_unchanged": skipped_unchanged,
            "embeddings_upserted": embedded_new,
            "store": self.store.stats(),
        }

    def retrieve(
        self,
        query: str,
        top_k: int = 8,
        min_score: Optional[float] = None,
        dedupe_by_source: bool = False,
    ) -> List[Dict[str, Any]]:
        qvec = self.embed_texts([query])
        ids, mat, chunks = self.store.get_all_embeddings(self.embed_model)
        if mat.shape[0] == 0:
            return []

        sims = cosine_sim_matrix(mat, qvec).reshape(-1)
        order = np.argsort(-sims)

        results = []
        seen_sources = set()
        for idx in order[: max(top_k * 5, top_k)]:
            score = float(sims[idx])
            if (min_score is not None) and (score < min_score):
                continue
            c = chunks[int(idx)]
            if dedupe_by_source:
                if c.source_path in seen_sources:
                    continue
                seen_sources.add(c.source_path)
            results.append(
                {
                    "chunk_id": c.id,
                    "doc_id": c.doc_id,
                    "source_path": c.source_path,
                    "title": c.title,
                    "chunk_index": c.chunk_index,
                    "score": score,
                    "text": c.text,
                    "tokens": c.tokens,
                }
            )
            if len(results) >= top_k:
                break
        return results

    def build_prompt_with_context(
        self,
        query: str,
        retrieved: List[Dict[str, Any]],
        system_prompt: Optional[str] = None,
    ) -> List[Dict[str, str]]:
        if system_prompt is None:
            system_prompt = (
                "You are an internal company knowledge base assistant. "
                "Use ONLY the provided context to answer. "
                "If the answer is not in the context, say you don't know and ask a clarifying question. "
                "Cite sources by file name and chunk index in brackets like [file:chunk]."
            )

        context_blocks = []
        for r in retrieved:
            file_name = os.path.basename(r["source_path"]) or r["source_path"]
            context_blocks.append(
                f"SOURCE: {file_name}\nCHUNK: {r['chunk_index']}\nSCORE: {r['score']:.4f}\nCONTENT:\n{r['text']}"
            )
        context_text = "\n\n---\n\n".join(context_blocks) if context_blocks else "(no relevant documents retrieved)"

        user_content = (
            f"USER QUESTION:\n{query}\n\n"
            f"RETRIEVED CONTEXT (use all of it as needed):\n{context_text}\n\n"
            f"INSTRUCTIONS:\n"
            f"- Answer using the retrieved context.\n"
            f"- Include citations in the form [filename:chunk].\n"
            f"- If context is insufficient, say so and ask what to check next.\n"
        )

        return [{"role": "system", "content": system_prompt}, {"role": "user", "content": user_content}]

    def answer(
        self,
        query: str,
        top_k: int = 8,
        min_score: Optional[float] = None,
        dedupe_by_source: bool = False,
        temperature: float = 0.2,
        max_output_tokens: int = 900,
        system_prompt: Optional[str] = None,
        include_retrieved_in_response: bool = False,
    ) -> Dict[str, Any]:
        retrieved = self.retrieve(query, top_k=top_k, min_score=min_score, dedupe_by_source=dedupe_by_source)
        messages = self.build_prompt_with_context(query, retrieved, system_prompt=system_prompt)

        resp = self.client.chat.completions.create(
            model=self.chat_model,
            messages=messages,
            temperature=temperature,
            max_tokens=max_output_tokens,
        )
        text = resp.choices[0].message.content

        out = {"answer": text, "retrieved": retrieved if include_retrieved_in_response else None}
        return out


def cmd_index(args) -> int:
    client = OpenAI()
    store = SQLiteVectorStore(args.db)
    rag = RAG(store, client, embed_model=args.embed_model, chat_model=args.chat_model)
    patterns = args.patterns.split(",") if args.patterns else ["**/*.txt", "**/*.md"]
    res = rag.index_directory(
        docs_path=args.docs,
        patterns=[p.strip() for p in patterns if p.strip()],
        chunk_tokens=args.chunk_tokens,
        overlap_tokens=args.overlap_tokens,
        delete_missing=args.delete_missing,
    )
    print(json.dumps(res, indent=2))
    store.close()
    return 0


def cmd_ask(args) -> int:
    client = OpenAI()
    store = SQLiteVectorStore(args.db)
    rag = RAG(store, client, embed_model=args.embed_model, chat_model=args.chat_model)

    res = rag.answer(
        query=args.query,
        top_k=args.top_k,
        min_score=args.min_score,
        dedupe_by_source=args.dedupe_by_source,
        temperature=args.temperature,
        max_output_tokens=args.max_output_tokens,
        system_prompt=None,
        include_retrieved_in_response=args.show_context,
    )

    if args.show_context and res.get("retrieved") is not None:
        print("RETRIEVED DOCUMENTS:\n")
        for r in res["retrieved"]:
            fn = os.path.basename(r["source_path"]) or r["source_path"]
            print(f"- {fn}:{r['chunk_index']} score={r['score']:.4f} tokens={r['tokens']}")
        print("\nANSWER:\n")
        print(res["answer"])
    else:
        print(res["answer"])

    store.close()
    return 0


def cmd_chat(args) -> int:
    client = OpenAI()
    store = SQLiteVectorStore(args.db)
    rag = RAG(store, client, embed_model=args.embed_model, chat_model=args.chat_model)

    print("Internal KB Chat. Type 'exit' to quit.")
    while True:
        try:
            q = input("\nYou> ").strip()
        except (EOFError, KeyboardInterrupt):
            print()
            break
        if not q:
            continue
        if q.lower() in {"exit", "quit"}:
            break

        res = rag.answer(
            query=q,
            top_k=args.top_k,
            min_score=args.min_score,
            dedupe_by_source=args.dedupe_by_source,
            temperature=args.temperature,
            max_output_tokens=args.max_output_tokens,
            include_retrieved_in_response=args.show_context,
        )

        if args.show_context and res.get("retrieved") is not None:
            print("\nRetrieved:")
            for r in res["retrieved"]:
                fn = os.path.basename(r["source_path"]) or r["source_path"]
                print(f"  - [{fn}:{r['chunk_index']}] score={r['score']:.4f}")
        print("\nAssistant> " + (res["answer"] or "").strip())

    store.close()
    return 0


def build_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(description="Python RAG system (SQLite vector store + OpenAI embeddings + chat).")
    p.add_argument("--db", default=os.getenv("RAG_DB", "./rag_store.sqlite3"), help="Path to SQLite DB")
    p.add_argument("--embed-model", default=DEFAULT_EMBED_MODEL, help="Embedding model")
    p.add_argument("--chat-model", default=DEFAULT_CHAT_MODEL, help="Chat model")

    sub = p.add_subparsers(dest="cmd", required=True)

    p_index = sub.add_parser("index", help="Index documents into vector store")
    p_index.add_argument("--docs", required=True, help="Documents root directory")
    p_index.add_argument("--patterns", default="**/*.md,**/*.txt", help="Comma-separated glob patterns (recursive)")
    p_index.add_argument("--chunk-tokens", type=int, default=700, help="Chunk size (tokens)")
    p_index.add_argument("--overlap-tokens", type=int, default=120, help="Chunk overlap (tokens)")
    p_index.add_argument("--delete-missing", action="store_true", help="Delete docs no longer present under docs path")
    p_index.set_defaults(func=cmd_index)

    p_ask = sub.add_parser("ask", help="Ask a single question")
    p_ask.add_argument("--query", required=True, help="User query")
    p_ask.add_argument("--top-k", type=int, default=8, help="Number of chunks to retrieve")
    p_ask.add_argument("--min-score", type=float, default=None, help="Minimum cosine similarity threshold")
    p_ask.add_argument("--dedupe-by-source", action="store_true", help="At most one chunk per source file")
    p_ask.add_argument("--temperature", type=float, default=0.2)
    p_ask.add_argument("--max-output-tokens", type=int, default=900)
    p_ask.add_argument("--show-context", action="store_true", help="Print retrieved docs metadata before answer")
    p_ask.set_defaults(func=cmd_ask)

    p_chat = sub.add_parser("chat", help="Interactive chat")
    p_chat.add_argument("--top-k", type=int, default=8)
    p_chat.add_argument("--min-score", type=float, default=None)
    p_chat.add_argument("--dedupe-by-source", action="store_true")
    p_chat.add_argument("--temperature", type=float, default=0.2)
    p_chat.add_argument("--max-output-tokens", type=int, default=900)
    p_chat.add_argument("--show-context", action="store_true")
    p_chat.set_defaults(func=cmd_chat)

    return p


def main(argv: Optional[List[str]] = None) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)
    return args.func(args)


if __name__ == "__main__":
    raise SystemExit(main())